import { products } from "../data.js";
import type { Product } from "../types.js";

export interface ProductListFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

export interface ProductDetailResult extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export interface StockAdjustmentResult extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export function listProducts(filters: ProductListFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProduct(id: number): ProductDetailResult | null {
  const product = products.find((p) => p.id === id);
  if (!product) return null;

  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;

  return {
    ...product,
    isLowStock,
    inventoryValue,
  };
}

export function adjustStock(
  id: number,
  adjustment: number
): { error?: string; result?: StockAdjustmentResult } {
  const product = products.find((p) => p.id === id);
  if (!product) {
    return { error: "Product not found" };
  }

  if (typeof adjustment !== "number") {
    return { error: "adjustment must be a number" };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { error: "Insufficient stock" };
  }

  product.stock = newStock;

  return {
    result: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput } from "../types.js";

export interface OrderListFilters {
  userId?: number;
  status?: string;
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export function listOrders(filters: OrderListFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrder(id: number): EnrichedOrder | null {
  const order = orders.find((o) => o.id === id);
  if (!order) return null;

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(
  input: CreateOrderInput
): { error?: string; order?: Order } {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return { error: "userId and items are required" };
  }

  if (input.items.length === 0) {
    return { error: "Order must have at least one item" };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return { error: `Product ${item.productId} not found` };
    }

    if (item.quantity <= 0) {
      return { error: "Quantity must be positive" };
    }

    if (product.stock < item.quantity) {
      return { error: `Insufficient stock for ${product.name}` };
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { order };
}

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"];

const STATUS_TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

export function updateOrderStatus(
  id: number,
  status: string
): { error?: string; order?: Order } {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    return { error: "Order not found" };
  }

  if (!VALID_STATUSES.includes(status)) {
    return {
      error: `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`,
    };
  }

  if (!STATUS_TRANSITIONS[order.status]?.includes(status)) {
    return {
      error: `Cannot transition from ${order.status} to ${status}`,
    };
  }

  order.status = status as typeof order.status;

  return { order };
}

